   230→func bootstrapBackend(cfg config.ServerConfig, haveWAL bool) (backend *bootstrappedBackend, err error) {
   231→	beExist := fileutil.Exist(cfg.BackendPath())
   232→	ci := cindex.NewConsistentIndex(nil)
   233→	beHooks := serverstorage.NewBackendHooks(cfg.Logger, ci)
   234→	be := serverstorage.OpenBackend(cfg, beHooks)
   235→	defer func() {
   236→		if err != nil && be != nil {
   237→			be.Close()
   238→		}
   239→	}()
   240→	ci.SetBackend(be)
   241→	schema.CreateMetaBucket(be.BatchTx())
   242→	if cfg.BootstrapDefragThresholdMegabytes != 0 {
   243→		err = maybeDefragBackend(cfg, be)
   244→		if err != nil {
   245→			return nil, err
   246→		}
   247→	}
   248→	cfg.Logger.Info("restore consistentIndex", zap.Uint64("index", ci.ConsistentIndex()))
   249→
   250→	// TODO(serathius): Implement schema setup in fresh storage
   251→	var snapshot *raftpb.Snapshot
   252→	if haveWAL {
   253→		snapshot, be, err = recoverSnapshot(cfg, be, beExist, beHooks, ci)
   254→		if err != nil {
   255→			return nil, err
   256→		}
   257→	}
   258→	if beExist {
   259→		s1, s2 := be.Size(), be.SizeInUse()
   260→		cfg.Logger.Info(
   261→			"recovered v3 backend",
   262→			zap.Int64("backend-size-bytes", s1),
   263→			zap.String("backend-size", humanize.Bytes(uint64(s1))),
   264→			zap.Int64("backend-size-in-use-bytes", s2),
   265→			zap.String("backend-size-in-use", humanize.Bytes(uint64(s2))),
   266→		)
   267→		if err = schema.Validate(cfg.Logger, be.ReadTx()); err != nil {
   268→			cfg.Logger.Error("Failed to validate schema", zap.Error(err))
   269→			return nil, err
   270→		}
   271→	}
   272→
   273→	return &bootstrappedBackend{
   274→		beHooks:  beHooks,
   275→		be:       be,
   276→		ci:       ci,
   277→		beExist:  beExist,
   278→		snapshot: snapshot,
   279→	}, nil
   280→}
   281→
   282→func maybeDefragBackend(cfg config.ServerConfig, be backend.Backend) error {
   283→	size := be.Size()
   284→	sizeInUse := be.SizeInUse()
   285→	freeableMemory := uint(size - sizeInUse)
   286→	thresholdBytes := cfg.BootstrapDefragThresholdMegabytes * 1024 * 1024
   287→	if freeableMemory < thresholdBytes {
   288→		cfg.Logger.Info("Skipping defragmentation",
   289→			zap.Int64("current-db-size-bytes", size),
   290→			zap.String("current-db-size", humanize.Bytes(uint64(size))),
   291→			zap.Int64("current-db-size-in-use-bytes", sizeInUse),
   292→			zap.String("current-db-size-in-use", humanize.Bytes(uint64(sizeInUse))),
   293→			zap.Uint("bootstrap-defrag-threshold-bytes", thresholdBytes),
   294→			zap.String("bootstrap-defrag-threshold", humanize.Bytes(uint64(thresholdBytes))),
   295→		)
   296→		return nil
   297→	}
   298→	return be.Defrag()
   299→}
