   412→func recoverSnapshot(cfg config.ServerConfig, be backend.Backend, beExist bool, beHooks *serverstorage.BackendHooks, ci cindex.ConsistentIndexer) (*raftpb.Snapshot, backend.Backend, error) {
   413→	// Find a snapshot to start/restart a raft node
   414→	walSnaps, err := wal.ValidSnapshotEntries(cfg.Logger, cfg.WALDir())
   415→	if err != nil {
   416→		return nil, be, err
   417→	}
   418→
   419→	var snapshot *raftpb.Snapshot
   420→	if len(walSnaps) > 0 {
   421→		idx := len(walSnaps) - 1
   422→		snapshot = &raftpb.Snapshot{
   423→			Metadata: raftpb.SnapshotMetadata{
   424→				Term:  walSnaps[idx].GetTerm(),
   425→				Index: walSnaps[idx].GetIndex(),
   426→			},
   427→		}
   428→		if walSnaps[idx].ConfState != nil {
   429→			snapshot.Metadata.ConfState = *walSnaps[idx].ConfState
   430→		}
   431→		cfg.Logger.Info("constructed a snapshot from WAL record",
   432→			zap.Uint64("snapshot-index", snapshot.Metadata.Index),
   433→			zap.String("snapshot-size", humanize.Bytes(uint64(snapshot.Size()))),
   434→			zap.String("confState", snapshot.Metadata.ConfState.String()),
   435→			zap.Int("walSnaps-count", len(walSnaps)),
   436→		)
   437→	}
   438→
   439→	if snapshot != nil {
   440→		if be, err = serverstorage.RecoverSnapshotBackend(cfg, be, *snapshot, beExist, beHooks); err != nil {
   441→			cfg.Logger.Panic("failed to recover v3 backend from snapshot", zap.Error(err))
   442→		}
   443→		// A snapshot db may have already been recovered, and the old db should have
   444→		// already been closed in this case, so we should set the backend again.
   445→		ci.SetBackend(be)
   446→
   447→		if beExist {
   448→			// TODO: remove kvindex != 0 checking when we do not expect users to upgrade
   449→			// etcd from pre-3.0 release.
   450→			kvindex := ci.ConsistentIndex()
   451→			if kvindex < snapshot.Metadata.Index {
   452→				if kvindex != 0 {
   453→					return nil, be, fmt.Errorf("database file (%v index %d) does not match with snapshot (index %d)", cfg.BackendPath(), kvindex, snapshot.Metadata.Index)
   454→				}
   455→				cfg.Logger.Warn(
   456→					"consistent index was never saved",
   457→					zap.Uint64("snapshot-index", snapshot.Metadata.Index),
   458→				)
   459→			}
   460→		}
   461→	} else {
   462→		cfg.Logger.Info("No snapshot found. Recovering WAL from scratch!")
   463→	}
   464→	return snapshot, be, nil
   465→}
   466→
   467→func (c *bootstrappedCluster) Finalize(cfg config.ServerConfig, s *bootstrappedStorage) error {
   468→	if !s.wal.haveWAL {
   469→		c.cl.SetID(c.nodeID, c.cl.ID())
   470→	}
   471→	c.cl.SetBackend(schema.NewMembershipBackend(cfg.Logger, s.backend.be))
   472→	if s.wal.haveWAL {
   473→		c.cl.Recover(api.UpdateCapability)
   474→		if c.databaseFileMissing(s) {
   475→			bepath := cfg.BackendPath()
   476→			os.RemoveAll(bepath)
   477→			return fmt.Errorf("database file (%v) of the backend is missing", bepath)
   478→		}
   479→	}
   480→	scaleUpLearners := false
   481→	return membership.ValidateMaxLearnerConfig(cfg.MaxLearners, c.cl.Members(), scaleUpLearners)
   482→}
   483→
   484→func (c *bootstrappedCluster) databaseFileMissing(s *bootstrappedStorage) bool {
   485→	v3Cluster := c.cl.Version() != nil && !c.cl.Version().LessThan(semver.Version{Major: 3})
   486→	return v3Cluster && !s.backend.beExist
   487→}
   488→
   489→func bootstrapRaft(cfg config.ServerConfig, cluster *bootstrappedCluster, bwal *bootstrappedWAL) *bootstrappedRaft {
   490→	switch {
   491→	case !bwal.haveWAL && !cfg.NewCluster:
   492→		return bootstrapRaftFromCluster(cfg, cluster.cl, nil, bwal)
   493→	case !bwal.haveWAL && cfg.NewCluster:
   494→		return bootstrapRaftFromCluster(cfg, cluster.cl, cluster.cl.MemberIDs(), bwal)
   495→	case bwal.haveWAL:
   496→		return bootstrapRaftFromWAL(cfg, bwal)
   497→	default:
   498→		cfg.Logger.Panic("unsupported bootstrap config")
   499→		return nil
   500→	}
   501→}
   502→
   503→func bootstrapRaftFromCluster(cfg config.ServerConfig, cl *membership.RaftCluster, ids []types.ID, bwal *bootstrappedWAL) *bootstrappedRaft {
   504→	member := cl.MemberByName(cfg.Name)
   505→	peers := make([]raft.Peer, len(ids))
   506→	for i, id := range ids {
   507→		var ctx []byte
   508→		ctx, err := json.Marshal((*cl).Member(id))
   509→		if err != nil {
   510→			cfg.Logger.Panic("failed to marshal member", zap.Error(err))
   511→		}
   512→		peers[i] = raft.Peer{ID: uint64(id), Context: ctx}
   513→	}
   514→	cfg.Logger.Info(
   515→		"starting local member",
   516→		zap.String("local-member-id", member.ID.String()),
   517→		zap.String("cluster-id", cl.ID().String()),
   518→	)
   519→	s := bwal.MemoryStorage()
   520→	return &bootstrappedRaft{
   521→		lg:        cfg.Logger,
   522→		heartbeat: time.Duration(cfg.TickMs) * time.Millisecond,
   523→		config:    raftConfig(cfg, uint64(member.ID), s),
   524→		peers:     peers,
   525→		storage:   s,
   526→	}
   527→}
   528→
   529→func bootstrapRaftFromWAL(cfg config.ServerConfig, bwal *bootstrappedWAL) *bootstrappedRaft {
   530→	s := bwal.MemoryStorage()
   531→	return &bootstrappedRaft{
   532→		lg:        cfg.Logger,
   533→		heartbeat: time.Duration(cfg.TickMs) * time.Millisecond,
   534→		config:    raftConfig(cfg, uint64(bwal.meta.nodeID), s),
   535→		storage:   s,
   536→	}
   537→}
   538→
   539→func raftConfig(cfg config.ServerConfig, id uint64, s *raft.MemoryStorage) *raft.Config {
   540→	return &raft.Config{
   541→		ID:              id,
   542→		ElectionTick:    cfg.ElectionTicks,
   543→		HeartbeatTick:   1,
   544→		Storage:         s,
   545→		MaxSizePerMsg:   maxSizePerMsg,
   546→		MaxInflightMsgs: maxInflightMsgs,
   547→		CheckQuorum:     true,
   548→		PreVote:         cfg.PreVote,
   549→		Logger:          NewRaftLoggerZap(cfg.Logger.Named("raft")),
   550→	}
   551→}
   552→
   553→func (b *bootstrappedRaft) newRaftNode(ss *snap.Snapshotter, wal *wal.WAL, cl *membership.RaftCluster) *raftNode {
   554→	var n raft.Node
   555→	if len(b.peers) == 0 {
   556→		n = raft.RestartNode(b.config)
   557→	} else {
   558→		n = raft.StartNode(b.config, b.peers)
   559→	}
   560→	raftStatusMu.Lock()
   561→	raftStatus = n.Status
   562→	raftStatusMu.Unlock()
   563→	return newRaftNode(
   564→		raftNodeConfig{
   565→			lg:          b.lg,
   566→			isIDRemoved: func(id uint64) bool { return cl.IsIDRemoved(types.ID(id)) },
   567→			Node:        n,
   568→			heartbeat:   b.heartbeat,
   569→			raftStorage: b.storage,
   570→			storage:     serverstorage.NewStorage(b.lg, wal, ss),
   571→		},
   572→	)
   573→}
   574→
   575→func bootstrapWALFromSnapshot(cfg config.ServerConfig, snapshot *raftpb.Snapshot, ci cindex.ConsistentIndexer) *bootstrappedWAL {
   576→	wal, st, ents, snap, meta := openWALFromSnapshot(cfg, snapshot)
   577→	bwal := &bootstrappedWAL{
   578→		lg:       cfg.Logger,
   579→		w:        wal,
   580→		st:       st,
   581→		ents:     ents,
   582→		snapshot: snap,
   583→		meta:     meta,
   584→		haveWAL:  true,
   585→	}
   586→
   587→	if cfg.ForceNewCluster {
   588→		consistentIndex := ci.ConsistentIndex()
   589→		oldCommitIndex := bwal.st.Commit
   590→		// If only `HardState.Commit` increases, HardState won't be persisted
   591→		// to disk, even though the committed entries might have already been
   592→		// applied. This can result in consistent_index > CommitIndex.
   593→		//
   594→		// When restarting etcd with `--force-new-cluster`, all uncommitted
   595→		// entries are dropped. To avoid losing entries that were actually
   596→		// committed, we reset Commit to max(HardState.Commit, consistent_index).
   597→		//
   598→		// See: https://github.com/etcd-io/raft/pull/300 for more details.
   599→		bwal.st.Commit = max(oldCommitIndex, consistentIndex)
   600→
   601→		// discard the previously uncommitted entries
   602→		bwal.ents = bwal.CommitedEntries()
   603→		entries := bwal.NewConfigChangeEntries()
   604→		// force commit config change entries
   605→		bwal.AppendAndCommitEntries(entries)
   606→		cfg.Logger.Info(
   607→			"forcing restart member",
   608→			zap.String("cluster-id", meta.clusterID.String()),
   609→			zap.String("local-member-id", meta.nodeID.String()),
   610→			zap.Uint64("wal-commit-index", oldCommitIndex),
   611→			zap.Uint64("commit-index", bwal.st.Commit),
   612→		)
   613→	} else {
   614→		cfg.Logger.Info(
   615→			"restarting local member",
   616→			zap.String("cluster-id", meta.clusterID.String()),
   617→			zap.String("local-member-id", meta.nodeID.String()),
   618→			zap.Uint64("commit-index", bwal.st.Commit),
   619→		)
   620→	}
   621→	return bwal
   622→}
