    69→// If logerr is true, it prints out more error messages.
    70→func getClusterFromRemotePeers(lg *zap.Logger, urls []string, timeout time.Duration, logerr bool, rt http.RoundTripper) (*membership.RaftCluster, error) {
    71→	if lg == nil {
    72→		lg = zap.NewNop()
    73→	}
    74→	cc := &http.Client{
    75→		Transport: rt,
    76→		Timeout:   timeout,
    77→		CheckRedirect: func(req *http.Request, via []*http.Request) error {
    78→			return http.ErrUseLastResponse
    79→		},
    80→	}
    81→	for _, u := range urls {
    82→		addr := u + "/members"
    83→		resp, err := cc.Get(addr)
    84→		if err != nil {
    85→			if logerr {
    86→				lg.Warn("failed to get cluster response", zap.String("address", addr), zap.Error(err))
    87→			}
    88→			continue
    89→		}
    90→		b, err := io.ReadAll(resp.Body)
    91→		resp.Body.Close()
    92→		if err != nil {
    93→			if logerr {
    94→				lg.Warn("failed to read body of cluster response", zap.String("address", addr), zap.Error(err))
    95→			}
    96→			continue
    97→		}
    98→		var membs []*membership.Member
    99→		if err = json.Unmarshal(b, &membs); err != nil {
   100→			if logerr {
   101→				lg.Warn("failed to unmarshal cluster response", zap.String("address", addr), zap.Error(err))
   102→			}
   103→			continue
   104→		}
   105→		id, err := types.IDFromString(resp.Header.Get("X-Etcd-Cluster-ID"))
   106→		if err != nil {
   107→			if logerr {
   108→				lg.Warn(
   109→					"failed to parse cluster ID",
   110→					zap.String("address", addr),
   111→					zap.String("header", resp.Header.Get("X-Etcd-Cluster-ID")),
   112→					zap.Error(err),
   113→				)
   114→			}
   115→			continue
   116→		}
   117→
   118→		// check the length of membership members
   119→		// if the membership members are present then prepare and return raft cluster
   120→		// if membership members are not present then the raft cluster formed will be
   121→		// an invalid empty cluster hence return failed to get raft cluster member(s) from the given urls error
   122→		if len(membs) > 0 {
   123→			return membership.NewClusterFromMembers(lg, id, membs), nil
   124→		}
   125→		return nil, fmt.Errorf("failed to get raft cluster member(s) from the given URLs")
   126→	}
   127→	return nil, fmt.Errorf("could not retrieve cluster information from the given URLs")
   128→}
