   135→		if m.Name == local {
   136→			continue
   137→		}
   138→		us = append(us, m.PeerURLs...)
   139→	}
   140→	sort.Strings(us)
   141→	return us
   142→}
   143→
   144→// getMembersVersions returns the versions of the members in the given cluster.
   145→// The key of the returned map is the member's ID. The value of the returned map
   146→// is the semver versions string, including server and cluster.
   147→// If it fails to get the version of a member, the key will be nil.
   148→func getMembersVersions(lg *zap.Logger, cl *membership.RaftCluster, local types.ID, rt http.RoundTripper, timeout time.Duration) map[string]*version.Versions {
   149→	members := cl.Members()
   150→	vers := make(map[string]*version.Versions)
   151→	for _, m := range members {
   152→		if m.ID == local {
   153→			cv := "not_decided"
   154→			if cl.Version() != nil {
   155→				cv = cl.Version().String()
   156→			}
   157→			vers[m.ID.String()] = &version.Versions{Server: version.Version, Cluster: cv}
   158→			continue
   159→		}
   160→		ver, err := getVersion(lg, m, rt, timeout)
   161→		if err != nil {
   162→			lg.Warn("failed to get version", zap.String("remote-member-id", m.ID.String()), zap.Error(err))
   163→			vers[m.ID.String()] = nil
   164→		} else {
   165→			vers[m.ID.String()] = ver
   166→		}
   167→	}
   168→	return vers
   169→}
   170→
   171→// allowedVersionRange decides the available version range of the cluster that local server can join in;
   172→// if the downgrade enabled status is true, the version window is [oneMinorHigher, oneMinorHigher]
   173→// if the downgrade is not enabled, the version window is [MinClusterVersion, localVersion]
   174→func allowedVersionRange(downgradeEnabled bool) (minV *semver.Version, maxV *semver.Version) {
   175→	minV = semver.Must(semver.NewVersion(version.MinClusterVersion))
   176→	maxV = semver.Must(semver.NewVersion(version.Version))
   177→	maxV = &semver.Version{Major: maxV.Major, Minor: maxV.Minor}
   178→
   179→	if downgradeEnabled {
   180→		// Todo: handle the case that downgrading from higher major version(e.g. downgrade from v4.0 to v3.x)
   181→		maxV.Minor = maxV.Minor + 1
   182→		minV = &semver.Version{Major: maxV.Major, Minor: maxV.Minor}
   183→	}
   184→	return minV, maxV
   185→}
   186→
   187→// isCompatibleWithCluster return true if the local member has a compatible version with
   188→// the current running cluster.
   189→// The version is considered as compatible when at least one of the other members in the cluster has a
   190→// cluster version in the range of [MinV, MaxV] and no known members has a cluster version
   191→// out of the range.
   192→// We set this rule since when the local member joins, another member might be offline.
   193→func isCompatibleWithCluster(lg *zap.Logger, cl *membership.RaftCluster, local types.ID, rt http.RoundTripper, timeout time.Duration) bool {
   194→	vers := getMembersVersions(lg, cl, local, rt, timeout)
   195→	minV, maxV := allowedVersionRange(getDowngradeEnabledFromRemotePeers(lg, cl, local, rt, timeout))
   196→	return isCompatibleWithVers(lg, vers, local, minV, maxV)
   197→}
   198→
   199→func isCompatibleWithVers(lg *zap.Logger, vers map[string]*version.Versions, local types.ID, minV, maxV *semver.Version) bool {
   200→	var ok bool
   201→	for id, v := range vers {
   202→		// ignore comparison with local version
   203→		if id == local.String() {
   204→			continue
   205→		}
   206→		if v == nil {
   207→			continue
   208→		}
   209→		clusterv, err := semver.NewVersion(v.Cluster)
   210→		if err != nil {
   211→			lg.Warn(
   212→				"failed to parse cluster version of remote member",
   213→				zap.String("remote-member-id", id),
   214→				zap.String("remote-member-cluster-version", v.Cluster),
   215→				zap.Error(err),
   216→			)
   217→			continue
   218→		}
   219→		if clusterv.LessThan(*minV) {
   220→			lg.Warn(
   221→				"cluster version of remote member is not compatible; too low",
   222→				zap.String("remote-member-id", id),
   223→				zap.String("remote-member-cluster-version", clusterv.String()),
   224→				zap.String("minimum-cluster-version-supported", minV.String()),
   225→			)
   226→			return false
   227→		}
   228→		if maxV.LessThan(*clusterv) {
   229→			lg.Warn(
   230→				"cluster version of remote member is not compatible; too high",
   231→				zap.String("remote-member-id", id),
   232→				zap.String("remote-member-cluster-version", clusterv.String()),
   233→				zap.String("maximum-cluster-version-supported", maxV.String()),
   234→			)
   235→			return false
   236→		}
   237→		ok = true
   238→	}
   239→	return ok
   240→}
   241→
   242→// getVersion returns the Versions of the given member via its
   243→// peerURLs. Returns the last error if it fails to get the version.
   244→func getVersion(lg *zap.Logger, m *membership.Member, rt http.RoundTripper, timeout time.Duration) (*version.Versions, error) {
   245→	cc := &http.Client{
   246→		Transport: rt,
   247→		Timeout:   timeout,
   248→		CheckRedirect: func(req *http.Request, via []*http.Request) error {
   249→			return http.ErrUseLastResponse
   250→		},
   251→	}
   252→	var (
   253→		err  error
   254→		resp *http.Response
   255→	)
   256→
   257→	for _, u := range m.PeerURLs {
   258→		addr := u + "/version"
   259→		resp, err = cc.Get(addr)
   260→		if err != nil {
   261→			lg.Warn(
   262→				"failed to reach the peer URL",
   263→				zap.String("address", addr),
   264→				zap.String("remote-member-id", m.ID.String()),
   265→				zap.Error(err),
   266→			)
   267→			continue
   268→		}
   269→		var b []byte
   270→		b, err = io.ReadAll(resp.Body)
   271→		resp.Body.Close()
   272→		if err != nil {
   273→			lg.Warn(
   274→				"failed to read body of response",
   275→				zap.String("address", addr),
   276→				zap.String("remote-member-id", m.ID.String()),
   277→				zap.Error(err),
   278→			)
   279→			continue
   280→		}
   281→		var vers version.Versions
   282→		if err = json.Unmarshal(b, &vers); err != nil {
   283→			lg.Warn(
   284→				"failed to unmarshal response",
   285→				zap.String("address", addr),
   286→				zap.String("remote-member-id", m.ID.String()),
   287→				zap.Error(err),
   288→			)
   289→			continue
   290→		}
   291→		return &vers, nil
   292→	}
   293→	return nil, err
   294→}
   295→
   296→func promoteMemberHTTP(ctx context.Context, url string, id uint64, peerRt http.RoundTripper) ([]*membership.Member, error) {
   297→	cc := &http.Client{
   298→		Transport: peerRt,
   299→		CheckRedirect: func(req *http.Request, via []*http.Request) error {
   300→			return http.ErrUseLastResponse
   301→		},
   302→	}
   303→	// TODO: refactor member http handler code
   304→	// cannot import etcdhttp, so manually construct url
   305→	requestURL := url + "/members/promote/" + fmt.Sprintf("%d", id)
   306→	req, err := http.NewRequest(http.MethodPost, requestURL, nil)
   307→	if err != nil {
   308→		return nil, err
   309→	}
   310→
   311→	// add the auth token via HTTP header if present in gRPC metadata
   312→	if md, ok := metadata.FromIncomingContext(ctx); ok {
   313→		ts, ok := md[rpctypes.TokenFieldNameGRPC]
   314→		if !ok {
   315→			ts, ok = md[rpctypes.TokenFieldNameSwagger]
   316→		}
   317→
   318→		if ok && len(ts) > 0 {
   319→			token := ts[0]
   320→			req.Header.Set("Authorization", token)
   321→		}
   322→	}
   323→
   324→	req = req.WithContext(ctx)
   325→	resp, err := cc.Do(req)
   326→	if err != nil {
   327→		return nil, err
   328→	}
   329→	defer resp.Body.Close()
   330→	b, err := io.ReadAll(resp.Body)
   331→	if err != nil {
   332→		return nil, err
   333→	}
   334→
   335→	if resp.StatusCode == http.StatusRequestTimeout {
   336→		return nil, errors.ErrTimeout
   337→	}
   338→	if resp.StatusCode == http.StatusPreconditionFailed {
   339→		// both ErrMemberNotLearner and ErrLearnerNotReady have same http status code
   340→		if strings.Contains(string(b), errors.ErrLearnerNotReady.Error()) {
   341→			return nil, errors.ErrLearnerNotReady
   342→		}
   343→		if strings.Contains(string(b), membership.ErrMemberNotLearner.Error()) {
   344→			return nil, membership.ErrMemberNotLearner
   345→		}
   346→		return nil, fmt.Errorf("member promote: unknown error(%s)", b)
   347→	}
   348→	if resp.StatusCode == http.StatusNotFound {
   349→		return nil, membership.ErrIDNotFound
   350→	}
   351→
   352→	if resp.StatusCode != http.StatusOK { // all other types of errors
   353→		return nil, fmt.Errorf("member promote: unknown error(%s)", b)
   354→	}
   355→
   356→	var membs []*membership.Member
   357→	if err := json.Unmarshal(b, &membs); err != nil {
   358→		return nil, err
   359→	}
   360→	return membs, nil
   361→}
   362→
   363→// getDowngradeEnabledFromRemotePeers will get the downgrade enabled status of the cluster.
   364→func getDowngradeEnabledFromRemotePeers(lg *zap.Logger, cl *membership.RaftCluster, local types.ID, rt http.RoundTripper, timeout time.Duration) bool {
   365→	members := cl.Members()
   366→
   367→	for _, m := range members {
   368→		if m.ID == local {
   369→			continue
   370→		}
   371→		enable, err := getDowngradeEnabled(lg, m, rt, timeout)
   372→		if err == nil {
   373→			// Since the "/downgrade/enabled" serves linearized data,
   374→			// this function can return once it gets a non-error response from the endpoint.
   375→			return enable
   376→		}
   377→		lg.Warn("failed to get downgrade enabled status", zap.String("remote-member-id", m.ID.String()), zap.Error(err))
   378→	}
   379→	return false
   380→}
   381→
   382→// getDowngradeEnabled returns the downgrade enabled status of the given member
   383→// via its peerURLs. Returns the last error if it fails to get it.
   384→func getDowngradeEnabled(lg *zap.Logger, m *membership.Member, rt http.RoundTripper, timeout time.Duration) (bool, error) {
   385→	cc := &http.Client{
   386→		Transport: rt,
   387→		Timeout:   timeout,
   388→		CheckRedirect: func(req *http.Request, via []*http.Request) error {
   389→			return http.ErrUseLastResponse
   390→		},
   391→	}
   392→	var (
   393→		err  error
   394→		resp *http.Response
   395→	)
   396→
   397→	for _, u := range m.PeerURLs {
   398→		addr := u + DowngradeEnabledPath
   399→		resp, err = cc.Get(addr)
   400→		if err != nil {
   401→			lg.Warn(
   402→				"failed to reach the peer URL",
   403→				zap.String("address", addr),
   404→				zap.String("remote-member-id", m.ID.String()),
   405→				zap.Error(err),
   406→			)
   407→			continue
   408→		}
   409→		var b []byte
   410→		b, err = io.ReadAll(resp.Body)
   411→		resp.Body.Close()
   412→		if err != nil {
   413→			lg.Warn(
   414→				"failed to read body of response",
   415→				zap.String("address", addr),
   416→				zap.String("remote-member-id", m.ID.String()),
   417→				zap.Error(err),
   418→			)
   419→			continue
   420→		}
   421→		var enable bool
   422→		if enable, err = strconv.ParseBool(string(b)); err != nil {
   423→			lg.Warn(
   424→				"failed to convert response",
   425→				zap.String("address", addr),
   426→				zap.String("remote-member-id", m.ID.String()),
   427→				zap.Error(err),
   428→			)
   429→			continue
   430→		}
   431→		return enable, nil
   432→	}
   433→	return false, err
   434→}
   435→
   436→func convertToClusterVersion(v string) (*semver.Version, error) {
   437→	ver, err := semver.NewVersion(v)
   438→	if err != nil {
   439→		// allow input version format Major.Minor
   440→		ver, err = semver.NewVersion(v + ".0")
   441→		if err != nil {
   442→			return nil, errors.ErrWrongDowngradeVersionFormat
   443→		}
   444→	}
   445→	// cluster version only keeps major.minor, remove patch version
   446→	ver = &semver.Version{Major: ver.Major, Minor: ver.Minor}
   447→	return ver, nil
   448→}
   449→
   450→func GetMembershipInfoInV2Format(lg *zap.Logger, cl *membership.RaftCluster) []byte {
   451→	st := v2store.New(StoreClusterPrefix, StoreKeysPrefix)
   452→	cl.Store(st)
   453→	d, err := st.SaveNoCopy()
   454→	if err != nil {
   455→		lg.Panic("failed to save v2 store", zap.Error(err))
   456→	}
   457→	return d
   458→}
